/**
 * Sends a specified amount of ETH to a target address.
 * @param {string} toAddress The recipient's Ethereum address.
 * @param {string} amountInEth The amount of ETH to send (as a string, e.g., "0.01").
 * @returns {Promise<ethers.TransactionReceipt>} The transaction receipt.
 */
async function sendEther(toAddress, amountInEth) {
    try {
        console.log(`Attempting to send ${amountInEth} ETH to ${toAddress}...`);

        const tx = {
            to: toAddress,
            value: ethers.parseEther(amountInEth), // Converts ETH string to BigNumber wei
            // Optional: You can specify gasLimit and gasPrice/maxFeePerGas/maxPriorityFeePerGas here
            // gasLimit: 21000,
            // maxFeePerGas: ethers.parseUnits("100", "gwei"),
            // maxPriorityFeePerGas: ethers.parseUnits("2", "gwei"),
        };

        const transactionResponse = await wallet.sendTransaction(tx);
        console.log(`Transaction hash: ${transactionResponse.hash}`);
        console.log("Waiting for transaction to be mined...");

        const receipt = await transactionResponse.wait();
        console.log("Transaction confirmed.");
        console.log("Receipt:", receipt);
        return receipt;
    } catch (error) {
        console.error("Failed to send ETH:", error);
        throw error; // Re-throw to allow caller to handle
    }
}

